member.example:
Bind the SphereCollider center property using a serialized binder field — the target SphereCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SphereColliderCenterBinder _center;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _center;
    }


Bind the SphereCollider center property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private SphereCollider _sphereCollider;
        
        private SphereColliderCenterBinder Center =>
            new(_sphereCollider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _center;
    }

Switch the SphereCollider center between two Vector3 values using a serialized binder field — the target SphereCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SphereColliderCenterSwitcherBinder _isActive;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }


Switch the SphereCollider center between two Vector3 values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private SphereCollider _sphereCollider;
        
        private SphereColliderCenterSwitcherBinder IsActive => new(
            _sphereCollider,
            trueValue: new Vector3(0, 1, 0),
            falseValue: Vector3.zero);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }
